mapper.select:
SELECT property_type
FROM properties
WHERE property_id = #{propertyId}

SELECT

FROM favorite_apartments fa
INNER JOIN properties p ON p.property_id = fa.property_id
WHERE fa.user_id = #{userId}
  AND fa.property_id = #{propertyId}
LIMIT 1

mapper.insert:
INSERT IGNORE INTO favorite_apartments (
    user_id,
    property_id
) VALUES (
    #{userId},
    #{propertyId}
)

mapper.delete:
DELETE FROM favorite_apartments
WHERE user_id = #{userId}
  AND property_id = #{propertyId}

mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM favorite_apartments
    WHERE user_id = #{userId}
      AND property_id = #{propertyId}
)
